import { application } from "./application"

import FlashController from "./flash_controller"
application.register("flash", FlashController)

import FormSubmitController from "./form_submit_controller"
application.register("form-submit", FormSubmitController)

import HabitCheckboxController from "./habit_checkbox_controller"
application.register("habit-checkbox", HabitCheckboxController)

import HabitFormController from "./habit_form_controller"
application.register("habit-form", HabitFormController)

import HabitMenuController from "./habit_menu_controller"
application.register("habit-menu", HabitMenuController)

import HabitRecordController from "./habit_record_controller"
application.register("habit-record", HabitRecordController)

import HabitSortController from "./habit_sort_controller"
application.register("habit-sort", HabitSortController)

import HelloController from "./hello_controller"
application.register("hello", HelloController)

import MobileMenuController from "./mobile_menu_controller"
application.register("mobile-menu", MobileMenuController)

// ── B-7 追加: voice-input コントローラーを登録する ──────────────────────────
//
// 【なぜ手動で登録するのか】
//   Rails の stimulus:manifest:update コマンドは controllers/ 配下の
//   ファイルを自動検出して index.js を更新する。
//   ただし、コマンドを手動実行するまで反映されないため、
//   ここに手動で追記しておく。
//   次回 stimulus:manifest:update を実行すると自動で整理される。
//
// 【登録名 "voice-input" について】
//   HTML 側の data-controller="voice-input" と対応する。
//   キャメルケースのファイル名（VoiceInputController）が
//   ケバブケース（voice-input）に変換されてHTMLの属性名になる。
import VoiceInputController from "./voice_input_controller"
application.register("voice-input", VoiceInputController)
// ──────────────────────────────────────────────────────────────────────────

// ── C-1 追加: priority-card コントローラーを登録する ─────────────────────────
//
// 【このコントローラーの役割】
//   タスク作成フォームの優先度カード（Must/Should/Could）の
//   選択状態をビジュアルで切り替える。
//   Tailwind の peer-checked だけでは「チェックが外れた状態」のリセットができないため
//   Stimulus で明示的にクラスを管理する。
//
// 【登録名 "priority-card" について】
//   ファイル名 priority_card_controller.js が
//   ケバブケース priority-card に変換されて HTML の data-controller 値になる。
import PriorityCardController from "./priority_card_controller"
application.register("priority-card", PriorityCardController)
